INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(101, '銀行預金の金利が0.001%、物価上昇率が2.0%の場合、預金の実質価値は？', '増える', '変わらない', '目減りする', '2倍になる', 'C', 'お金の額面が変わらなくても、モノの値段が上がれば買える量は減ります。', 1),
(102, '「名目賃金」が上がっても、それ以上に物価が上がっている状態を何と呼ぶ？', '実質賃金の低下', '名目賃金の上昇', 'インフレ率', '複利効果', 'A', '給料の額面が増えても、生活が楽にならない典型的なパターンです。', 1),
(103, '円安（1ドル100円→150円）になると、輸入商品の価格は？', '上がる', '下がる', '変わらない', '半分になる', 'A', '海外からエネルギーや食料を買うコストが上がるため、国内の生活費も上昇します。', 1),
(104, '利子が利子を生んで雪だるま式に増える効果を何と呼ぶ？', '単利効果', '複利効果', '金利効果', '貯蓄効果', 'B', '時間を味方につけることで、資産形成のスピードが加速します。', 1),
(105, '「72の法則」で年利3%運用した場合、資産が2倍になる期間は？', '12年', '18年', '24年', '36年', 'C', '72÷3=24年。逆に銀行預金（0.001%）だと72000年かかります。', 1),
(106, '現金だけで資産を持つことの最大のリスクは？', 'インフレリスク', '盗難リスク', '紛失リスク', '税金リスク', 'A', '「元本保証」は額面の話であり、購買力は保証されていません。', 1),
(107, '投資期間が長くなるほど、リターンの振れ幅（リスク）は？', '大きくなる', '変わらない', '平準化される', 'ゼロになる', 'C', '短期ではブレますが、長期的には経済成長に合わせてプラスに収束しやすい傾向があります。', 1),
(108, '金利がプラスの世界で、「今すぐ100万円」と「1年後100万円」ではどちらが価値が高い？', '今すぐ', '1年後', '同じ', 'わからない', 'A', '今もらって運用すれば1年後には増えているため、現在の100万円の方が価値が高いです。', 1),
(109, '現在の銀行預金が資産形成に向かない主な理由は？', '金利が極端に低い', '引き出しに時間がかかる', '税金が高い', '元本保証がない', 'A', '昔は預金だけで数％増えましたが、現在はほぼ増えません。', 1),
(110, '長期投資で重要な3要素は「金額」「利回り」ともう一つは？', '運', '才能', '時間', '学歴', 'C', '早く始めるほど複利効果を享受できます。', 1);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(201, '給与から天引きされる3大要素は、所得税、住民税、あと一つは？', '社会保険料', '固定資産税', '消費税', '法人税', 'A', '実は税金よりも社会保険料の負担の方が大きいケースが多いです。', 2),
(202, '住民税の支払額は、いつの年収に基づいて決まる？', '当年の年収', '前年の年収', '翌年の年収', '過去3年の平均', 'B', '新社会人の1年目は安く、2年目から手取りが減ります。', 2),
(203, '退職して無職になった場合でも、翌年に支払いが来る税金は？', '所得税', '住民税', '固定資産税', '消費税', 'B', '「後払い」の仕組みのため、退職時に貯蓄がないと詰みます。', 2),
(204, '会社員が確定申告をしなくて済むのは、会社が何をしてくれるから？', '年末調整', '源泉徴収', '給与計算', '税務申告', 'A', '生命保険料控除などはここで行いますが、医療費控除などは自分でやる必要があります。', 2),
(205, '年間の医療費がいくらを超えると、確定申告で医療費控除が受けられる？', '5万円', '10万円', '15万円', '20万円', 'B', '総所得金額等が200万円未満の人はその5%。家族分も合算可能です。', 2),
(206, 'ふるさと納税の実質的なメリットは、自己負担2,000円で何がもらえる？', '税金還付', '返礼品', 'ポイント', 'クーポン', 'B', '翌年の税金の前払いであり、節税そのものではありませんが、返礼品分が得になります。', 2),
(207, '厚生年金保険料は、会社と従業員でどのような割合で負担？', '全額会社負担', '全額従業員負担', '労使折半', '従業員が70%', 'C', '給与明細に見えている倍額が、将来のために納められています。', 2),
(208, '副業の所得（雑所得など）が年間いくらを超えると、確定申告が必要？', '10万円', '20万円', '30万円', '50万円', 'B', '20万円以下でも住民税の申告は必要です。', 2),
(209, '収入が増えるほど税率が高くなる日本の所得税の仕組みは？', '定率課税', '超過累進課税', '比例課税', '逆進課税', 'B', '稼げば稼ぐほど、税負担の割合は重くなります。', 2),
(210, '会社を辞めた際、健康保険を継続できる制度を何という？', '国民健康保険', '任意継続被保険者制度', '社会保険', '共済組合', 'B', '国保に切り替えるか、任意継続するか、保険料を比較して選ぶ必要があります。', 2);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(301, '生活防衛資金として確保しておくべき現金の目安は、生活費の何ヶ月分？', '1ヶ月分', '3〜6ヶ月分', '12ヶ月分', '24ヶ月分', 'B', '自営業者や不安定な職種の場合は1年分程度推奨されます。', 3),
(302, '節約効果が最も高く、一度見直すと効果がずっと続くのはどの支出？', '食費', '固定費', '交際費', '娯楽費', 'B', '家賃、保険、通信費、サブスクなど。変動費を削るよりストレスが少なく効果的です。', 3),
(303, 'クレジットカードの「リボ払い」の実質年率は、一般的に約何％？', '5%', '10%', '15〜18%', '25%', 'C', '消費者金融の借金とほぼ同じ高金利であり、絶対に避けるべきです。', 3),
(304, '毎月の返済額が一定で、借金総額が把握しにくくなる支払い方法は？', '一括払い', '分割払い', 'リボ払い', 'ボーナス払い', 'C', '残高が減らず、利息ばかり払い続ける「借金地獄」の入り口です。', 3),
(305, 'ボーナス払いを前提に毎月の赤字を補填する家計管理のリスクは？', 'ボーナスが増える', 'ボーナスカット時に家計が破綻', '税金が増える', '何もない', 'B', 'ボーナスはあくまで「臨時収入」として扱うのが鉄則です。', 3),
(306, '使っていないサブスク契約を見直すには、何を確認すべき？', '銀行の残高', 'クレジットカードの利用明細', '友人の意見', '広告', 'B', '記憶に頼らず、明細で「使途不明金」を洗い出しましょう。', 3),
(307, 'ネットショッピングで「後払い（BNPL）」を多用することのデメリットは？', '手数料が高い', '支出の痛みが遅れ、使いすぎる', '利用できる店が少ない', '何もない', 'B', '手元に現金がなくても買えるため、借金感覚が薄れがちです。', 3),
(308, '手取り月収の何割を「貯蓄・投資」に回すのが理想的な目安？', '5%', '10〜20%', '30%', '50%', 'B', '「収入－貯蓄＝生活費」の順序で管理することが重要です。', 3),
(309, 'コンビニでのちょこちょこ買い（ラテマネー）を防ぐのに有効な方法は？', '予算を決める', 'コンビニを増やす', '毎日行く', '何も考えない', 'A', '小さな出費も年間では大きな額になります。', 3),
(310, '急な出費（冠婚葬祭や家電故障）に備えるための資金管理のコツは？', '無視する', '借金する', '特別費を毎月積み立てる', 'クレジットカードを使う', 'C', '毎月の生活費とは別枠で管理することで、赤字を防ぎます。', 3);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(401, '民間の保険に入る前に、まず確認すべき日本の制度は？', '民間保険', '公的医療保険や遺族年金', 'クレジットカード保険', '旅行保険', 'B', '日本は公的保障が厚いため、民間の保険は「不足分」だけで十分です。', 4),
(402, '医療費が高額になった際、自己負担額を一定額以下に抑える制度は？', '高額療養費制度', '医療費控除', '確定申告', '保険金請求', 'A', '一般的な年収なら、月額約8〜9万円以上の医療費は戻ってきます。', 4),
(403, '独身で扶養家族がいない場合、高額な「死亡保障」は必要？', '必要', '不要', 'どちらでもよい', 'わからない', 'B', '死亡保障は「残された家族の生活費」のためにあるものです。', 4),
(404, '貯蓄型保険の一般的なデメリットは？', '手数料が高く、投資効率が悪い', '保障が手厚い', '解約が簡単', '税金がかからない', 'A', '「掛け捨て」で安く保障を買い、浮いたお金をNISA等で運用する方が合理的です。', 4),
(405, '病気や怪我で働けなくなった時の収入減少をカバーする保険は？', '生命保険', '医療保険', '就業不能保険', '火災保険', 'C', '医療保険よりも、働けないリスクへの備えの方が優先度が高い場合があります。', 4),
(406, '会社員が病気で休んだ際、給与の約2/3が最長1年6ヶ月支給される制度は？', '有給休暇', '傷病手当金', '失業保険', 'ボーナス', 'B', 'この制度があるため、会社員は医療保険の優先度が下がります。', 4),
(407, '自転車事故で他人に怪我をさせた場合に備える保険は？', '生命保険', '自動車保険', '個人賠償責任保険', '火災保険', 'C', '損害賠償は数千万円になることもあるため、必須級の保険です。', 4),
(408, '保険営業担当者が提案するプランは、誰のために最適化されている可能性がある？', '顧客', '販売者', '保険会社', '国', 'B', '自分の身は自分で守るため、言われるがままに入らないリテラシーが必要です。', 4),
(409, '住宅ローンを組む際に入る「団信」の役割は？', '火災に備える', '死亡時にローンの残債がゼロになる', '病気に備える', '地震に備える', 'B', 'これがあるため、住宅購入後は既存の生命保険を減額できる可能性があります。', 4),
(410, '保険の見直しを行うべきタイミングは？', '毎月', '毎年', 'ライフイベント時', '10年ごと', 'C', '結婚、出産、住宅購入、子供の独立などのライフイベント時。必要な保障額は人生のステージによって変動します。', 4);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(501, 'NISAの最大のメリットは？', '手数料が安い', '投資の利益に税金がかからない', '元本保証', '高利回り', 'B', '通常は約20%引かれますが、それがまるまる手元に残ります。', 5),
(502, '市場全体の値動きに連動する成果を目指す投資信託を何という？', 'アクティブファンド', 'インデックスファンド', 'ヘッジファンド', 'バランスファンド', 'B', '低コストで分散投資ができるため、長期投資の王道とされます。', 5),
(503, '投資信託を持っている間、ずっと払い続ける手数料を何という？', '購入手数料', '信託報酬', '解約手数料', '売買手数料', 'B', '長期投資では、この手数料が0.1%違うだけで最終結果に大きな差が出ます。', 5),
(504, '「卵を一つのカゴに盛るな」という格言が表す投資の基本原則は？', '集中投資', '分散投資', 'レバレッジ', 'デイトレード', 'B', '投資先を分けることで、一部がダメになっても資産全体を守れます。', 5),
(505, '毎月一定額を購入し、高い時は少なく、安い時は多く買う手法を何という？', 'スイッチング', 'ドル・コスト平均法', 'リバランス', 'ナンピン買い', 'B', '時間分散により、平均購入単価を平準化する効果があります。', 5),
(506, '「どの程度まで資産が減っても耐えられるか」という度合いを何という？', 'リスク許容度', 'リスクヘッジ', 'リスクプレミアム', 'リスクマネジメント', 'A', '年齢、資産額、性格などで異なり、これを超えた投資は危険です。', 5),
(507, '資産配分の比率が崩れた時に、元に戻す作業を何という？', 'スイッチング', 'ポートフォリオ', 'リバランス', 'ヘッジ', 'C', '高くなったものを売り、安くなったものを買うことで、パフォーマンスを維持します。', 5),
(508, '暴落が起きた際、積立投資家が取ってはいけない行動は？', '積立継続', '狼狽売り', 'リバランス', '何もしない', 'B', '安い時に買えるチャンスを放棄し、損失を確定させることになります。', 5),
(509, '全世界株式（オール・カントリー）一本に投資することのメリットは？', '手数料が安い', '世界中の経済成長を取り込める', '元本保証', '短期で儲かる', 'B', 'どの国が伸びるか予想する必要がなくなります。', 5),
(510, 'NISA口座は1人につき何口座持てる？', '無制限', '3口座', '2口座', '1口座', 'D', '金融機関の変更は可能ですが、年単位の手続きが必要です。', 5);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(601, '人生の三大資金とは、教育資金、住宅資金、あと一つは？', '結婚資金', '老後資金', '旅行資金', '車購入資金', 'B', '最も金額が大きく、準備期間が長いのが老後資金です。', 6),
(602, 'iDeCoの掛金が全額所得控除になることのメリットは？', '手数料が安くなる', '毎年の所得税・住民税が安くなる', '元本保証', '投資が不要', 'B', '運用益非課税だけでなく、拠出時にも節税できる強力な制度です。', 6),
(603, 'iDeCoや企業型DCの原則的な引き出し可能年齢は？', '50歳', '55歳', '60歳', '65歳', 'C', '老後資金用のため、途中解約が原則できません（強力なロック機能）。', 6),
(604, '企業型DCのデフォルト商品が「定期預金」の場合のデメリットは？', '手数料が高い', 'リスクが高い', 'インフレで実質価値が目減り', '元本割れする', 'C', '自分で投資信託などに配分変更（スイッチング）する必要があります。', 6),
(605, '転職時、企業型DCの資産を次の会社やiDeCoに移せる仕組みを何という？', 'ポータビリティ', 'トランスファー', 'スイッチング', 'マッチング', 'A', '放置すると手数料が引かれ続ける自動移換などの不利益を被ります。', 6),
(606, '企業型DCで、会社の掛金に上乗せして自分でも掛金を出せる制度は？', 'マッチング拠出', 'ダブル拠出', '追加拠出', '個人拠出', 'A', '制度がある場合は、積極的に活用すべきお得な仕組みです。', 6),
(607, '退職金を受け取る際、税金が大幅に安くなる控除を何という？', '給与所得控除', '退職所得控除', '基礎控除', '配偶者控除', 'B', '勤続年数が長いほど控除額が増え、税負担が軽くなります。', 6),
(608, 'ねんきん定期便で確認できる重要な情報は、納付額と何？', '税金額', '将来受け取れる年金の見込額', '貯金額', '投資額', 'B', '自分の老後収入のベースを知ることが、不足額計算の第一歩です。', 6),
(609, '老後資金の取り崩し方法で、資産を長持ちさせるには「定額」と「定率」どちら？', '定額', '定率', 'どちらでもよい', 'わからない', 'B', '例：毎年残高の4%ずつ。暴落時に取り崩す額が減るため、資産が枯渇するリスクを下げられます。', 6),
(610, 'iDeCoを一時金か年金で受け取る場合、どちらが得？', '一時金', '年金', 'ケースバイケース', '同じ', 'C', '退職金や公的年金の額によるため、退職所得控除と公的年金等控除の枠をどう使うかで税金が変わります。', 6);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(701, '権利が確定し、ストックオプションやRSUを行使・売却できるようになることを何という？', 'ベスティング', 'エクササイズ', 'グラント', 'クリフ', 'A', '会社に留まり続けるインセンティブとして期間が設定されています。', 7),
(702, '給与と資産の大半が同じ会社に依存している状態のリスクは？', '分散リスク', '集中リスク', '流動性リスク', 'カントリーリスク', 'B', '会社が傾いた時、給与も資産も同時に失う（「卵を一つのカゴ」状態）で、非常に危険です。', 7),
(703, 'ストックオプション（税制適格）を行使して株を取得し、売却した場合の課税タイミングは？', '行使時', '売却時', '付与時', '課税されない', 'B', '行使時には課税されず、売却時に譲渡所得として課税されます（要件を満たした場合）。', 7),
(704, '含み益をあてにして生活水準を上げることの危険性は？', '税金が増える', '株価暴落で価値がゼロになる可能性', '手数料が高い', '何もない', 'B', '「捕らぬ狸の皮算用」になり、税金やローンだけが残るリスクがあります。', 7),
(705, '海外本社から付与されたRSUは、日本の税制上、原則としてどの所得になる？', '給与所得', '事業所得', '雑所得', '配当所得', 'A', '権利確定（Vest）した時点で給与として課税され、確定申告が必要になるケースが多いです。', 7),
(706, '自社株を売却する際、インサイダー取引規制に抵触しないよう注意すべきことは？', '特に注意不要', '決算発表前などの売買禁止期間を守る', '毎日売買する', '大量に売買する', 'B', '重要な未公開情報を知っている立場での売買は犯罪になります。', 7),
(707, '自社株がVestされたら取るべき合理的な行動の一つは？', '持ち続ける', '即売却し、分散資産に買い換える', '全額使う', '放置する', 'B', '感情的には持ちたいかもしれませんが、リスク管理上は分散が正解です。', 7),
(708, 'ストックオプションに「行使期限」はある？', 'ない', 'ある', 'わからない', 'ケースバイケース', 'B', '一般的に退職後や付与後10年など。期限を過ぎると紙切れになるため、管理が必要です。', 7),
(709, '外貨建ての自社株を持つ場合に発生する、株価以外のリスクは？', 'インフレリスク', '為替リスク', '金利リスク', '税金リスク', 'B', '株価が上がっても、極端な円高になると円換算の価値は減ります。', 7),
(710, 'SO/RSUは、資産ポートフォリオの中でどのような位置付けと考えるべき？', '主要資産', 'ボーナス（臨時収入）', '老後資金', '生活基盤', 'B', '不確実性が高すぎるため、老後資金の計算にこれを含めるのは危険です。', 7);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(801, '住宅を購入する際、最も重視すべき「売却時のしやすさ」を指す言葉は？', '流動性', '利回り', '資産性', '収益性', 'A', '転勤や離婚など、売りたい時に売れる物件かどうかがリスク管理の鍵です。', 8),
(802, '手取り収入に対する住居費（返済額＋管理費等）の安全圏の比率は？', '10%以内', '20〜25%以内', '30%以内', '40%以内', 'B', '30%を超えると家計が圧迫され、教育費や老後資金が貯まらなくなります。', 8),
(803, '住宅ローン金利で、市場金利に応じて返済額が変わるタイプは？', '固定金利', '変動金利', 'フラット35', 'ミックスローン', 'B', '金利が低いのがメリットですが、上昇リスクを負うのは借り手です。', 8),
(804, '日本の木造住宅は、一般的に築何年程度で建物の評価額がほぼゼロになる？', '10年', '20〜25年', '30年', '50年', 'B', '土地の価値が残らない場所で新築を買うと、資産価値は激減します。', 8),
(805, '「持ち家は資産になる」という考え方の落とし穴は？', '固定資産税がかかる', '多くの場合は負債で、売却額が残債を下回るリスクがある', '引っ越しできない', '管理が大変', 'B', '自分が住む家はキャッシュを生まないため、会計的には「資産」でも実質は「消費」に近いです。', 8),
(806, '住宅ローン控除とは、年末のローン残高の一定割合がどうなる制度？', '利息が減る', '所得税・住民税から控除される', 'ローンが免除される', '金利が下がる', 'B', '金利が低い場合、支払う利息より戻ってくる税金の方が多い「逆ザヤ」になることもあります。', 8),
(807, '低金利時代に、住宅ローンを「繰り上げ返済」することのデメリットは？', '手数料がかかる', '手元の流動性が減り、運用益の機会を捨てる', '税金が増える', '何もない', 'B', '0.5%のローンを返すより、NISAで3%運用した方が合理的という考え方です。', 8),
(808, '賃貸の最大のメリットの一つは、ライフスタイルに合わせた何ができること？', '投資', '住み替え', '売却', 'リフォーム', 'B', '家族構成の変化や騒音トラブルなどに対し、引っ越しで解決できる強みがあります。', 8),
(809, 'マンション購入時に、ローン返済以外にかかる毎月の固定費は管理費と何？', '修繕積立金', '火災保険', '固定資産税', '駐車場代', 'A', '築年数が経つと値上げされることが多く、注意が必要です。', 8),
(810, 'リセールバリューを維持しやすい物件の特徴は？', '築年数が古い', '駅から遠い', '駅近・人気エリア・管理状態が良い', '安い', 'C', '「自分が住みたい家」と「他人が買いたい家」は必ずしも一致しません。', 8);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(901, '「元本保証で、月利3%（年利36%）配当」という投資話。これは何である可能性が高い？', '優良投資', '詐欺', '銀行預金', '国債', 'B', 'ローリスク・ハイリターンは金融の世界には存在しません。', 9),
(902, '新規出資者から集めたお金を古参への配当に回し、最後は破綻する詐欺手法は？', 'ネズミ講', 'ポンジ・スキーム', 'マルチ商法', 'インサイダー取引', 'B', '詐欺の9割はこの手口です。最初は本当に配当が出るため信じてしまいます。', 9),
(903, 'FXや暗号資産で、手持ち資金の何倍もの取引を行い、わずかな変動で資金を失う仕組みは？', 'スイングトレード', 'レバレッジ', 'デイトレード', 'スキャルピング', 'B', '借金をして投資しているのと同じであり、初心者には推奨されません。', 9),
(904, 'SNSやマッチングアプリで知り合った外国人などから投資を勧められる詐欺は？', 'オレオレ詐欺', 'ロマンス詐欺', 'フィッシング詐欺', '振り込め詐欺', 'B', '恋愛感情や親近感を利用して、偽の投資サイトに入金させます。', 9),
(905, '銀行や証券会社の窓口でおすすめされる商品の多くは、なぜ購入すべきでない？', '元本割れする', '販売手数料や信託報酬が高い', 'リスクが低い', '売れ筋商品', 'B', '良い商品は宣伝しなくても売れるため、窓口で営業する必要がありません。', 9),
(906, '「あなただけに教える」「未公開情報」というフレーズが出たら、どう判断すべき？', '信用する', '100%詐欺か違法勧誘', '検討する', '友人に聞く', 'B', '本当に儲かる話を赤の他人に教える人はいません。', 9),
(907, '投資対象について、SNSの情報だけでなく必ず確認すべきものは？', '友人の意見', '一次情報（公式サイト、目論見書）', '広告', 'テレビ', 'B', 'インフルエンサーの発言はポジショントークや案件である可能性があります。', 9),
(908, '詐欺被害に遭わないための最強の防衛策は、「理解できないもの」にどうする？', '投資する', '投資しない', '友人に聞く', '勉強する', 'B', '仕組みがわからないものにお金を出すのは投資ではなくギャンブルです。', 9),
(909, '金融商品取引業の登録がない業者が投資を勧誘することは？', '合法', '違法', 'グレーゾーン', 'わからない', 'B', '金融庁のサイトで登録業者かどうかを確認できます。', 9),
(910, '節税目的でワンルームマンション投資を勧誘された際、注意すべきリスクは？', '税金が増える', '空室・家賃下落・修繕費で収支マイナス', '金利が上がる', '何もない', 'B', '節税効果は最初だけで、後は負の遺産になるケースが多発しています。', 9);
INSERT INTO quizzes (id, question, option_a, option_b, option_c, option_d, correct_answer, explanation, chapter_id) VALUES
(1001, '資産形成を確実に実行するために、意志力に頼らず行うべき設定は？', '手動入金', '自動積立', '毎月考える', '気が向いたら', 'B', '「余ったら貯める」ではなく「先に引く（先取り貯蓄）」が鉄則です。', 10),
(1002, '投資を始める際、「勉強してから」と「少額で走りながら学ぶ」どちらが推奨される？', '勉強してから', '少額で走りながら学ぶ', 'どちらでもよい', 'わからない', 'B', '実際に自分のお金が動く経験をしないと、本当のリテラシーは身につきません。', 10),
(1003, '家計簿をつけるのが面倒な人が導入すべきツールは？', '紙の家計簿', '家計簿アプリ', 'エクセル', '何もしない', 'B', '自動でデータ化することで、現状把握のコストを極限まで下げます。', 10),
(1004, '大きな目標に圧倒されず行動するために重要なことは？', 'あきらめる', '目標を細分化する', '人に任せる', '何もしない', 'B', '今日できる具体的な「ベイビーステップ」に落とし込みます（例：月1万円の積立設定）。', 10),
(1005, '積立設定をした後、日々の株価チェックはどのくらいの頻度が推奨される？', '毎日', '毎週', 'ほとんど見なくてよい', '毎時間', 'C', '頻繁に見ると感情が揺さぶられ、余計な売買をしてしまう原因になります。', 10),
(1006, '「忙しくて時間がない」を理由に後回しにしないための、行動科学的なコツは？', '諦める', '「いつ、どこで、何を」具体的にスケジュールに入れる', '後で考える', '忘れる', 'B', 'If-Thenプランニング。「いつかやる」という予定は永遠に来ません。', 10),
(1007, '資産形成のモチベーション維持のため、他人と比較すべき？', 'すべき', 'しない（過去の自分と比較）', 'どちらでもよい', 'わからない', 'B', 'SNSの億り人などと比較しても焦りが生まれるだけで、百害あって一利なしです。', 10),
(1008, '良い習慣を続けるために、邪魔な手間を減らすことを何という？', 'フリクションの低減', 'ハードルを上げる', '複雑化', '何もしない', 'A', '逆に、散財などの悪い習慣には手間を増やすのが有効です。', 10),
(1009, '夫婦や家族で資産形成を行う際、最も重要なアクションは？', '秘密にする', '価値観や目標を共有し、話し合う', '別々に管理', '無視する', 'B', '片方が節約しても片方が散財すれば穴の空いたバケツと同じです。', 10),
(1010, 'この研修が終わった後、最初に行うべきアクションは？', '何もしない', '今日学んだ内容の一つを即実行する', '忘れる', '後で考える', 'B', '「いい話を聞いた」で終わらせず、行動を変えることがこの研修のゴールです。', 10);
